lessons.solution:
interface Heroi {
  nome: string;
  hp: number;
  hpMax: number;
  ataque: number;
  defesa: number;
  ouro: number;
}

interface Monstro {
  nome: string;
  hp: number;
  ataque: number;
  xpRecompensa: number;
}

const heroi: Heroi = {
  nome: "Aria",
  hp: 100,
  hpMax: 100,
  ataque: 20,
  defesa: 5,
  ouro: 50
};

const monstros: Monstro[] = [
  { nome: "Slime", hp: 30, ataque: 8, xpRecompensa: 10 },
  { nome: "Goblin", hp: 50, ataque: 15, xpRecompensa: 25 },
  { nome: "Dragão", hp: 120, ataque: 30, xpRecompensa: 100 }
];

function mostrarStatus(h: Heroi): void {
  console.log(`[${h.nome}] HP: ${h.hp}/${h.hpMax}`);
}

function atacarMonstro(h: Heroi, m: Monstro): void {
  const dano: number = h.ataque - 2;
  m.hp = m.hp - dano;
  console.log(`${h.nome} ataca ${m.nome} por ${dano} de dano!`);
}

function monstroAtaca(m: Monstro, h: Heroi): void {
  const dano: number = Math.max(1, m.ataque - h.defesa);
  h.hp = h.hp - dano;
  console.log(`${m.nome} ataca ${h.nome} por ${dano} de dano!`);
}

function batalhar(h: Heroi, m: Monstro): void {
  console.log(`=== Batalha: ${h.nome} vs ${m.nome} ===`);
  while (h.hp > 0 && m.hp > 0) {
    atacarMonstro(h, m);
    if (m.hp <= 0) {
      console.log(`${m.nome} foi derrotado! +${m.xpRecompensa} XP`);
      break;
    }
    monstroAtaca(m, h);
    mostrarStatus(h);
  }
  if (h.hp <= 0) {
    console.log(`${h.nome} foi derrotada...`);
  }
}

batalhar(heroi, monstros[0]);
